import { IDisposable } from "./disposable";
import { IHostAPI } from "../host/smartdesign_host";
import { ICommand, IGroup } from "./command";
import { Communicator } from "./communicator";

export class CommandRegistry {
    private commandRegistry: Map<string, ICommand> = new Map<string, ICommand>();

    constructor(private communicator: Communicator<IHostAPI>) {
        this.communicator.expose(
            {
                invokeCommand: (commandId) => this.invokeCommand(commandId),
            },
            "invokeCommand",
        );
    }

    private invokeCommand(commandId: string) {
        const command = this.commandRegistry.get(commandId);
        if (command) {
            command.callback();
        }
    }

    contributeGroup(command: IGroup): IDisposable {
        return this.contributeCommand({ ...command, group: true });
    }

    contributeCommand(command: ICommand | IGroup): IDisposable {
        if (!command.id) {
            throw new Error("Command must be defined with a non-empty, unique id!");
        }
        if (this.commandRegistry.has(command.id)) {
            throw new Error(`Command is already defined with the id "${command.id}"!`);
        }

        if (this.isCommand(command)) {
            this.commandRegistry.set(command.id, command);
        }
        this.communicator.invoke("contributeCommand", command);

        return {
            dispose: () => {
                this.commandRegistry.delete(command.id);
                this.communicator.invoke("revokeCommand", command.id);
            },
        };
    }

    private isCommand(command: IGroup | ICommand): command is ICommand {
        return command && !(command as IGroup).group && (command as ICommand).callback != null;
    }
}
