class Navigator implements INavigator {
    constructor(private communicator: Communicator<IHostAPI>) {}

    navigate(intent: string, options?: INavigationOptions): Promise<void> {
        return this.communicator.invokeRelaxed("navigate", intent, options);
    }
    navigateWithRecord(
        objectType: string,
        gguid: string,
        intent?: string,
        options?: IRecordNavigationOptions,
    ): Promise<void> {
        return this.communicator.invokeRelaxed("navigateWithRecord", objectType, gguid, intent, options);
    }
    navigateWithRecords(
        objectType: string,
        selection: INavigationSelection,
        intent?: string,
        options?: INavigationOptions,
    ): Promise<void> {
        return this.communicator.invokeRelaxed("navigateWithRecords", objectType, selection, intent, options);
    }
    navigateToDossier(
        source: ISingleSelection,
        selection?: ISingleSelection,
        intent?: string,
        navigateToDossier?: string[],
        options?: INavigationOptions,
    ): Promise<void> {
        return this.communicator.invokeRelaxed(
            "navigateToDossier",
            source,
            selection,
            intent,
            navigateToDossier,
            options,
        );
    }
}

class NavigationImpl implements SmartDesign.INavigation {
    private _supportedNavigationModes: BackNavigationMode[];
    private _intents: string[];
    private _reloadSupported: boolean;
    private _recordPreviewSupported: boolean;
    private _navigator: INavigator;
    private _navigationScheduler: (actor) => void = (actor) =>
        setTimeout(() => {
            actor();
        }, 0);

    constructor(
        initParameters: InitParameters<any>,
        private communicator: Communicator<IHostAPI>,
    ) {
        this._intents = (initParameters.intents || []).slice();
        this._reloadSupported = initParameters.reloadSupported;
        this._recordPreviewSupported = initParameters.recordPreviewSupported;
        this._supportedNavigationModes = (initParameters.backNavigationModes || []).slice();
        this._navigator = new Navigator(communicator);
    }
    public get intents(): string[] {
        return this._intents.slice();
    }

    public isBackwardNavigationModeSupported(mode: BackNavigationMode): boolean {
        return mode === "NONE" || this._supportedNavigationModes.indexOf(mode) > -1;
    }

    public setBackwardNavigationMode(mode: BackNavigationMode): Promise<void> {
        if (!this.isBackwardNavigationModeSupported(mode)) {
            return Promise.reject(new Error("Navigation mode is not supported"));
        }
        return this.communicator.invoke("setBackwardNavigationMode", mode);
    }

    public navigate(...args: any[]): INavigationBuilder {
        let intent;
        if (args.length >= 1) {
            intent = args[0];
        }
        const navigationBuilder: INavigationBuilder = new NavigationBuilder(this._navigator).withIntent(intent);
        this.triggerNavigation(navigationBuilder);
        return navigationBuilder;
    }
    public navigateWithRecord(...args: any[]): INavigationWithRecordBuilder {
        let objectType;
        let gguid;
        let intent;
        if (args.length >= 2) {
            objectType = args[0];
            gguid = args[1];
        }
        if (args.length >= 3) {
            intent = args[2];
        }
        const navigationBuilder: INavigationWithRecordBuilder = new NavigationWithRecordBuilder(this._navigator)
            .withObjectType(objectType)
            .withGguid(gguid)
            .withIntent(intent);
        this.triggerNavigation(navigationBuilder);
        return navigationBuilder;
    }
    public navigateWithRecords(...args: any[]): INavigationWithRecordsBuilder {
        let objectType;
        let gguid;
        let gguids;
        let intent;
        if (args.length >= 2) {
            objectType = args[0];
            gguids = args[1];
        }
        if (args.length >= 3) {
            gguid = args[2];
        }
        if (args.length >= 4) {
            intent = args[3];
        }
        const navigationBuilder: INavigationWithRecordsBuilder = new NavigationWithRecordsBuilder(this._navigator)
            .withObjectType(objectType)
            .withGguids(gguids)
            .withSelectedGguid(gguid)
            .withIntent(intent);
        this.triggerNavigation(navigationBuilder);
        return navigationBuilder;
    }
    public navigateToDossier(...args: any[]): INavigationWithDossierBuilder {
        let objectType;
        let gguid;
        let intent;
        if (args.length >= 2) {
            objectType = args[0];
            gguid = args[1];
        }
        if (args.length >= 3) {
            intent = args[2];
        }
        const navigationBuilder: INavigationWithDossierBuilder = new NavigationWithDossierBuilder(this._navigator)
            .withSourceGguid(gguid)
            .withSourceObjectType(objectType)
            .withIntent(intent);
        this.triggerNavigation(navigationBuilder);
        return navigationBuilder;
    }
    public get reloadSupported(): boolean {
        return this._reloadSupported;
    }
    public reload(): Promise<void> {
        if (!this.reloadSupported) {
            return Promise.reject(new Error("Reload is not supported"));
        }
        return this.communicator.invoke("reload");
    }
    public navigateBack(): Promise<void> {
        return this.communicator.invoke("navigateBack");
    }
    public navigateHome(): Promise<void> {
        return this.communicator.invoke("navigateHome");
    }
    public get recordPreviewSupported(): boolean {
        return this._recordPreviewSupported;
    }
    public showRecordPreview(objectType: string, gguid: string): Promise<void> {
        if (!this._recordPreviewSupported) {
            return Promise.reject(new Error("Record preview API is not supported"));
        }
        return this.communicator.invokeRelaxed("showRecordPreview", objectType, gguid);
    }
    public hideRecordPreview(): Promise<void> {
        if (!this._recordPreviewSupported) {
            return Promise.reject(new Error("Record preview API is not supported"));
        }
        return this.communicator.invokeRelaxed("hideRecordPreview");
    }
    public urlChanged(url: string): Promise<void> {
        return this.communicator.invoke("urlChanged", url);
    }
    private triggerNavigation(navigationBuilder: INavigationBuilder): void {
        this._navigationScheduler(() => navigationBuilder.navigate());
    }
}

class SearchImpl implements SmartDesign.ISearch {
    private _openSearchSupported: boolean;
    private isSearchPending: boolean;

    constructor(
        private initParameters: InitParameters<any>,
        private communicator: Communicator<IHostAPI>,
    ) {
        this._openSearchSupported = initParameters.openSearchSupported;
    }

    public get openSearchSupported(): boolean {
        return this._openSearchSupported;
    }

    public openSearch(objectType: string, query?: SearchQuery): Promise<OpenSearchResponse> {
        if (!this.openSearchSupported) {
            return Promise.reject(new Error("OpenSearch api method is not supported"));
        }
        if (this.isSearchPending) {
            return Promise.reject(
                new Error(
                    "The OpenSearch method can not be executed simultaneously, the operation is already in a pending state.",
                ),
            );
        }

        const openSearch: Promise<OpenSearchResponse> = this.communicator.invokeRelaxed(
            "openSearch",
            objectType,
            query,
        );
        this.isSearchPending = true;
        return openSearch
            .then((p) => {
                this.isSearchPending = false;
                return p;
            })
            .catch((e) => {
                this.isSearchPending = false;
                throw e;
            });
    }
}

