class DialogApiImpl implements SmartDesign.IDialogApi {
    private _openSupported: boolean;

    constructor(
        private initParameters: InitParameters<any>,
        private communicator: Communicator<IHostAPI>,
    ) {
        this._openSupported = initParameters.openDialogSupported;
    }

    public get openSupported(): boolean {
        return this._openSupported;
    }

    public alert(title: string, message: string, style?: DialogStyle): Promise<IDialogResult> {
        return this.open({
            title,
            message,
            style,
        });
    }
    public confirm(title: string, message: string, style?: DialogStyle): Promise<IDialogResult> {
        return this.open({
            title,
            message,
            // eslint-disable-next-line camelcase
            buttons: DialogButtonPreset_YES_NO,
            style,
        });
    }
    public open(options: IDialogOptions): Promise<IDialogResult> {
        if (!this.openSupported) {
            return Promise.reject(new Error("Dialog API is not supported"));
        }

        const openDialog: Promise<IOpenDialogResponse> = this.communicator.invokeRelaxed(
            "openDialog",
            getEffectiveOptions(options),
        );

        return openDialog.then((response) => new DialogResultImpl(response));
    }
}

export type StateChangeCallback<T> = (newState: T, initialStateChange: boolean) => void;

class StateImpl<T extends ICustomState> implements SmartDesign.IState<T> {
    private _updateSupported: boolean;
    private _onChangeSupported: boolean;
    private _current: T & BasicState;
    private _callbacks: Array<StateChangeCallback<T & BasicState>> = [];

    constructor(
        initParameters: InitParameters<T>,
        private communicator: Communicator<IHostAPI>,
        private contextItemEnhancer: (item: IContextItem | IAggregation) => IContextItem | IAggregation,
        private fieldEnhancer: (field: FieldMetadata) => FieldMetadata,
    ) {
        this._updateSupported = initParameters.stateUpdateSupported;
        this._onChangeSupported = initParameters.stateOnChangeSupported;
        this._current = this.enhanceWithAPIMethods((initParameters.state || {}) as T & BasicState);
        this.communicator.expose(
            {
                setState: (state) => this.setState(state),
            },
            "setState",
        );
        /* Promise resolve does not work, as this class is created in a micro-task.
           In order to properly defer the initial state change event, we have to use
           setTimeout, so that the user land code can actually subscribe to it before
           firing the event.*/
        setTimeout(() => {
            this.fireStateChange(true);
        }, 0);
    }

    get onChangeSupported() {
        return this._onChangeSupported;
    }

    get updateSupported() {
        return this._updateSupported;
    }

    public onChange(callback: StateChangeCallback<T & BasicState>): IDisposable {
        this._callbacks.push(callback);
        return {
            dispose: () => {
                this._callbacks = this._callbacks.filter((p) => p !== callback);
            },
        };
    }

    public update(): Promise<T & BasicState> {
        if (!this.updateSupported) {
            return Promise.reject(new Error("UpdateState api method is not supported"));
        }
        return this.communicator.invoke("updateState", this._current).then(() => this._current);
    }

    get current(): T & BasicState {
        return this._current;
    }

    private setState(state: T & BasicState) {
        this._current = this.enhanceWithAPIMethods(state);
        this.fireStateChange(false);
    }

    private enhanceWithAPIMethods(state: T & BasicState): T & BasicState {
        if (state) {
            Object.keys(state).forEach((prop: keyof (T & BasicState)) => {
                const value = state[prop];
                if (isContextItem(value) || isFieldAggregation(value) || isScriptedAggregation(value)) {
                    (state[prop] as IContextItem | IAggregation) = this.contextItemEnhancer(value);
                } else if (isFieldMetadata(value)) {
                    (state[prop] as FieldMetadata) = this.fieldEnhancer(value);
                }
            });
        }
        return state;
    }

    private fireStateChange(initial: boolean) {
        if (this.onChangeSupported) {
            this._callbacks.forEach((p) => p(this._current, initial));
        }
    }
}

class ActivationChangeHandlerImpl implements IActivationChangeHandler {
    constructor(private handler: (message: ActivationMessage) => void) {}
    public onActivationChanged(message: ActivationMessage) {
        this.handler(message);
    }
}

class ActivationServiceImpl implements SmartDesign.IActivationService {
    constructor(private communicator: Communicator<IHostAPI>) {}

    public registerListener(actor: (message: ActivationMessage) => void): IDisposable {
        const api = new ActivationChangeHandlerImpl(actor);
        const disposables = getMethods(api).map((method) => this.communicator.expose(api, method));
        const dispose = () => {
            disposables.forEach((disposable) => disposable());
        };
        return { dispose };
    }
}

class InputDeviceImpl implements SmartDesign.IInputDeviceService {
    readonly devicesSupported: boolean;
    constructor(initParemeters: InitParameters<any>) {
        this.devicesSupported = initParemeters.devicesSupported;
    }

    getDevice<T extends InputDeviceType>(type: T): Promise<IInputDevice & { type: T }> {
        if (type != "BarcodeScanner" && type != "NFCReader") {
            return Promise.reject(new Error(`Accessing device with type "${type}" is not supported!`));
        }
        if (!this.devicesSupported) {
            return Promise.reject(new Error("Accessing devices are not supported!"));
        }
        return Promise.reject(new Error("Accessing devices are not implemented!"));
    }
}

class ContextImpl implements SmartDesign.IContext {
    private readonly primaryDataObject?: IDataObjectContextItem;
    private readonly primaryMassData?: IMassDataObjectContextItem;

    readonly primaryDataObjectAccessorSupported?: boolean;
    readonly primaryMassDataAccessorSupported?: boolean;
    readonly fieldValueConverterSupported?: boolean;

    constructor(
        initParameters: InitParameters<any>,
        private communicator: Communicator<IHostAPI>,
        private fieldValueChangeNotifier: FieldValueChangeNotifier,
        private contextItemChangeNotifier: ContextItemChangeNotifier,
    ) {
        const dataObjectContextItem = this.enhanceContextItemWithAPIMethods(initParameters.primaryDataObject);
        const primaryMassData = this.enhanceContextItemWithAPIMethods(initParameters.primaryMassData);

        this.primaryDataObject = dataObjectContextItem?.type == "DataObject" ? dataObjectContextItem : undefined;
        this.primaryMassData = primaryMassData?.type == "MassData" ? primaryMassData : undefined;

        this.primaryDataObjectAccessorSupported = initParameters.primaryDataObjectAccessorSupported;
        this.primaryMassDataAccessorSupported = initParameters.primaryMassDataAccessorSupported;

        this.fieldValueConverterSupported = initParameters.fieldValueConverterSupported;
    }

    enhanceContextItemWithAPIMethods(
        contextItem:
            | IContextItem
            | IAggregation
            | IDataObjectContextItemMetadata
            | IMassDataObjectContextItemMetadata
            | IDependentDataObjectsContextItemMetadata,
    ): IRuntimeContextItem | IRuntimeAggregation | undefined {
        if (!contextItem) {
            return undefined;
        }

        if (contextItem.type == "DataObject") {
            return new RuntimeDataObjectContextItem(
                contextItem,
                this.contextItemChangeNotifier,
                this.fieldValueChangeNotifier,
                this.communicator,
                (field) => this.enhanceFieldWithAPIMethods(field),
            );
        } else if (contextItem.type == "MassData") {
            return new RuntimeMassDataObjectContextItem<any>(
                contextItem,
                this.contextItemChangeNotifier,
                this.communicator,
                (field) => this.enhanceFieldWithAPIMethods(field),
            );
        } else if (contextItem.type == "DependentDataObjects") {
            return new RuntimeDependentDataObjectsContextItem<any>(
                contextItem,
                this.contextItemChangeNotifier,
                this.communicator,
                (field) => this.enhanceFieldWithAPIMethods(field),
            );
        } else if (isScriptedAggregation(contextItem)) {
            return new RuntimeScriptedAggregation(contextItem, this.contextItemChangeNotifier, this.communicator);
        } else if (isFieldAggregation(contextItem)) {
            return new RuntimeFieldAggregation(
                contextItem,
                this.contextItemChangeNotifier,
                this.communicator,
                (field) => this.enhanceFieldWithAPIMethods(field),
            );
        } else if (contextItem.type == "Aggregation") {
            if (contextItem.grouped) {
                return new RuntimeGroupedAggregation(contextItem, this.contextItemChangeNotifier, this.communicator);
            } else {
                return new RuntimeUngroupedAggregation(contextItem, this.contextItemChangeNotifier, this.communicator);
            }
        }

        return undefined;
    }

    enhanceFieldWithAPIMethods<T extends FieldMetadata>(field: T): T {
        if (!this.fieldValueConverterSupported) {
            return field;
        }

        if (isField(field)) {
            const initialValue = field.value;
            const initialFormattedValue = field.formattedValue;
            let value = initialValue;
            return {
                ...field,
                get value() {
                    return value;
                },
                set value(newValue: unknown) {
                    value = newValue;
                },
                get formattedValue() {
                    return value === initialValue ? initialFormattedValue : undefined;
                },
                converter: this.createConverter(field),
            };
        } else {
            return {
                ...field,
                converter: this.createConverter(field),
            };
        }
    }

    createConverter<T extends FieldMetadata>(field: T): FieldValueConverter<unknown, T["fieldType"]> {
        let formatter: FieldValueFormatter<unknown> | null = null;
        let parser: FieldValueParser<unknown> = null;

        if (isFormatSupportedField(field)) {
            formatter = {
                format: async (value: unknown) => {
                    if (isField(field) && field.value === value) {
                        if (field.formattedValue !== undefined) {
                            return field.formattedValue;
                        }
                    }

                    return this.communicator.invoke("formatFieldValue", field.objectTypeName, field.fieldName, {
                        value,
                    });
                },
            };
        }
        if (isParseSupportedField(field)) {
            parser = {
                parse: async (presentation: string) => {
                    return this.communicator.invoke(
                        "parseFieldValue",
                        field.objectTypeName,
                        field.fieldName,
                        presentation,
                    );
                },
            };
        }
        return {
            ...formatter,
            ...parser,
        };
    }

    getPrimaryDataObject<T = any>(): Promise<IDataObjectContextItem<T> | undefined> {
        if (!this.primaryDataObjectAccessorSupported) {
            return Promise.reject(new Error("Accessing the primary data object is not supported"));
        }
        return Promise.resolve(this.primaryDataObject);
    }

    getPrimaryMassData<T = any>(): Promise<IMassDataObjectContextItem<T> | undefined> {
        if (!this.primaryMassDataAccessorSupported) {
            return Promise.reject(new Error("Accessing the primary mass data is not supported"));
        }
        return Promise.resolve(this.primaryMassData);
    }
}

