class OverlayImpl implements SmartDesign.IOverlay {
    public readonly flyoutMenuSupported: boolean;
    public readonly radialMenuSupported: boolean;

    constructor(
        initParameters: InitParameters<any>,
        private communicator: Communicator<IHostAPI>,
    ) {
        this.flyoutMenuSupported = initParameters.flyoutMenuSupported;
        this.radialMenuSupported = initParameters.radialMenuSupported;
    }

    openFlyoutMenu(items: IFlyoutMenuItem[], positionOrArea: Coordinate | Area): Promise<IMenuItem | null> {
        if (!this.flyoutMenuSupported) {
            return Promise.reject(new Error("Opening a flyout menu is not supported!"));
        }
        const lastActiveElement = document.activeElement as HTMLElement;
        const result: Promise<IMenuItem | null> = this.communicator.invokeRelaxed(
            "openFlyoutMenu",
            items,
            positionOrArea,
        );
        result.then((p) => {
            if (lastActiveElement && lastActiveElement.focus) {
                lastActiveElement.focus();
            }
            return p;
        });
        return result;
    }

    openRadialMenu(
        items: IRadialMenuItem[],
        radialMenuOptions: RadialMenuOptions,
        position: Coordinate,
    ): Promise<IRadialMenuItem | null> {
        if (!this.radialMenuSupported) {
            return Promise.reject(new Error("Opening a radial menu is not supported!"));
        }
        const lastActiveElement = document.activeElement as HTMLElement;
        const result: Promise<IRadialMenuItem | null> = this.communicator.invokeRelaxed(
            "openRadialMenu",
            items,
            radialMenuOptions,
            position,
        );
        result.then((p) => {
            if (lastActiveElement && lastActiveElement.focus) {
                lastActiveElement.focus();
            }
            return p;
        });
        return result;
    }
}

