/**
 * Connects to the SmartDesign api.
 * @param targetOrigin The origin of the SmartDesign host, for hosted apps this can be omitted
 * @param target Accessor method to the window object of the SmartDesign host, usually ()=> window.parent
 * @param source Accessor method to the window object of the SmartDesign app frame, usually ()=> window
 * @param timeout Timeout for the sent messages
 */
export const connect = <T extends ICustomState>(
    targetOrigin: string = window.location.origin,
    target?: () => IEndpoint,
    source?: () => IEndpoint,
    timeout = 10000,
): Promise<SmartDesign.IAPI<T>> => {
    const delayedConnect = new Promise<SmartDesign.IAPI<T>>((resolve) => {
        setTimeout(() => {
            if ((window as any).SD_DIRECT) {
                (window as any).SD_DIRECT.initApp();
                const loop = () => {
                    if ((window as any).SD_DIRECT_API) {
                        resolve((window as any).SD_DIRECT_API);
                    } else {
                        requestAnimationFrame(loop);
                    }
                };
                loop();
            } else {
                resolve((window as any).SD_DIRECT_API);
            }
        }, 0);
    }).then((directApi) => {
        if (directApi) {
            return Promise.resolve(directApi as SmartDesign.IAPI<T>);
        } else {
            const waitForLoad = new Promise<any>((resolve) => {
                if (document.readyState === "complete") {
                    resolve(void 0);
                } else {
                    window.addEventListener("load", resolve);
                }
            });
            const sourceProvider = source ? source : () => window;
            const communicator = new Communicator<IHostAPI>(
                targetOrigin,
                target ? target : () => window.parent,
                sourceProvider,
                timeout,
            );
            const sourceWindow = sourceProvider() as Window;
            const origin = sourceWindow.location ? sourceWindow.location.origin : undefined;
            return waitForLoad
                .then(() => communicator.invoke("initApp", origin))
                .then((initParameters: InitParameters<T>) => {
                    return new SmartDesignAPIImpl<T>(initParameters, communicator);
                });
        }
    });

    return delayedConnect;
};

/**
 * Creates a tunnel for cross tab communication.
 * The resulting iframe should be appended to the html document, and then it can be used as a parameter to [[connect]].
 * @param host Url of the SmartDesign instance. e.g. https://mycompany.com/smartdesign or http://login.smartwe.de/SmartWe/
 * @param readyCallback Callback to execute after the tunnel is established
 */
export const createTunnel = (host = "", readyCallback: () => void): HTMLIFrameElement => {
    return createTunnelInternal(host, readyCallback);
};

export type StateValueTypes = FieldMetadata | boolean | number | string;

export interface ICustomState {
    [name: string]: StateValueTypes | StateValueTypes[] | Field<any> | IContextItem | IAggregation;
}

export const isField = (field: unknown): field is Field<unknown> => {
    return isFieldMetadata(field) && "value" in field;
};

export const isFieldMetadata = <T>(field: unknown): field is FieldMetadata<T> => {
    const asField = field as FieldMetadata<unknown>;
    return asField && asField.objectTypeName !== undefined && asField.fieldName !== undefined;
};

export const isSingleValueField = <T>(
    field: Field<T | T[]>,
): field is T extends Array<unknown> ? never : SingleValueField<T> => {
    return isField(field) && !Array.isArray(field.value);
};

export const isMultiValueField = <T>(
    field: Field<T | T[]>,
): field is T extends StringTreeSuggestPath[] ? never : MultiValueField<T> => {
    return isField(field) && !isStringTreeSuggestField(field) && Array.isArray(field.value);
};

export const isStringTreeSuggestField = <T>(field: Field<T | T[]>): field is StringTreeSuggestField => {
    return isField(field) && isStringTreeSuggestFieldMetadata(field);
};

export const isStringTreeSuggestFieldMetadata = (
    field: FieldMetadata<unknown>,
): field is StringTreeSuggestFieldMetadata => {
    return isFieldMetadata(field) && (field as StringTreeSuggestFieldMetadata).root != null;
};

export const isFieldMetadataWithPossibleValue = <
    T,
    FIELD_TYPE extends FieldType = FieldType,
    SUGGESTION_TYPE = UnWrapElementTypeIfArray<T>,
>(
    field: FieldMetadata<T, FIELD_TYPE>,
): field is FieldMetadataWithPossibleValue<T, SUGGESTION_TYPE, FIELD_TYPE> => {
    return isFieldMetadata(field) && (field as FieldMetadataWithPossibleValue<T, T, FIELD_TYPE>).possibleValues != null;
};

export const isContextItem = (object: unknown): object is IContextItem => {
    const potentialContextItem = object as IContextItem;
    const potentialFieldAggregation = object as IFieldAggregation;
    const potentialScriptedAggregation = object as IScriptedAggregation;
    return (
        potentialContextItem &&
        potentialContextItem.type != null &&
        potentialContextItem.name != null &&
        !potentialFieldAggregation.fieldAggregation &&
        !potentialScriptedAggregation.scriptedAggregation
    );
};

export const isAggregation = (object: unknown): object is IFieldAggregation => {
    if (isScriptedAggregation(object) || isFieldAggregation(object)) {
        return true;
    }
    return isContextItem(object) && object.type === "Aggregation";
};

export const isFieldAggregation = (object: unknown): object is IFieldAggregation => {
    const potentialFieldAggregation = object as IFieldAggregation;
    return (
        potentialFieldAggregation &&
        potentialFieldAggregation.type === "Aggregation" &&
        potentialFieldAggregation.name != null &&
        potentialFieldAggregation.fieldAggregation
    );
};

export const isScriptedAggregation = (object: unknown): object is IScriptedAggregation => {
    const potentialScriptedAggregation = object as IScriptedAggregation;
    return (
        potentialScriptedAggregation &&
        potentialScriptedAggregation.type === "ScriptedAggregation" &&
        potentialScriptedAggregation.name != null &&
        potentialScriptedAggregation.scriptedAggregation
    );
};

const isFormatSupportedField = (field: FieldMetadata): field is FieldMetadata<unknown, FieldTypesWithFormatSupport> => {
    return (
        isFieldMetadata(field) &&
        FIELD_TYPES_WITH_FORMAT_SUPPORT.indexOf(field.fieldType as FieldTypesWithFormatSupport) > -1
    );
};

const isParseSupportedField = (field: FieldMetadata): field is FieldMetadata<unknown, FieldTypesWithParseSupport> => {
    return (
        isFieldMetadata(field) &&
        FIELD_TYPES_WITH_PARSE_SUPPORT.indexOf(field.fieldType as FieldTypesWithParseSupport) > -1
    );
};

export const isFieldWithFormatSupport = <VALUE_TYPE = unknown, FIELD_TYPE extends FieldType = FieldType>(
    field: FieldMetadata<VALUE_TYPE, FIELD_TYPE>,
): field is FieldMetadata<VALUE_TYPE, FieldTypesWithFormatSupport & FIELD_TYPE> => {
    return (
        isFormatSupportedField(field) &&
        (field as FieldMetadata<VALUE_TYPE, FieldTypesWithFormatSupport>).converter &&
        (field as FieldMetadata<VALUE_TYPE, FieldTypesWithFormatSupport>).converter.format != null
    );
};
export const isFieldWithParseSupport = <VALUE_TYPE = unknown, FIELD_TYPE extends FieldType = FieldType>(
    field: FieldMetadata<VALUE_TYPE, FIELD_TYPE>,
): field is FieldMetadata<VALUE_TYPE, FieldTypesWithParseSupport & FIELD_TYPE> => {
    return (
        isParseSupportedField(field) &&
        (field as FieldMetadata<VALUE_TYPE, FieldTypesWithParseSupport>).converter &&
        (field as FieldMetadata<VALUE_TYPE, FieldTypesWithParseSupport>).converter.parse != null
    );
};

export const isCellWithFormatSupport = <VALUE_TYPE = unknown, FIELD_TYPE extends FieldType = FieldType>(
    cell: Cell<VALUE_TYPE, FIELD_TYPE>,
): cell is Cell<VALUE_TYPE, FieldTypesWithFormatSupport & FIELD_TYPE> => {
    return (
        cell &&
        cell.metadata &&
        FIELD_TYPES_WITH_FORMAT_SUPPORT.indexOf(cell.metadata.fieldType as FieldTypesWithFormatSupport) > -1 &&
        (cell as Cell<VALUE_TYPE, FieldTypesWithFormatSupport>).metadata.converter &&
        (cell as Cell<VALUE_TYPE, FieldTypesWithFormatSupport>).metadata.converter.format != null
    );
};

export const isCellWithParseSupport = <VALUE_TYPE = unknown, FIELD_TYPE extends FieldType = FieldType>(
    cell: Cell<VALUE_TYPE, FIELD_TYPE>,
): cell is Cell<VALUE_TYPE, FieldTypesWithParseSupport & FIELD_TYPE> => {
    return (
        cell &&
        cell.metadata &&
        FIELD_TYPES_WITH_PARSE_SUPPORT.indexOf(cell.metadata.fieldType as FieldTypesWithParseSupport) > -1 &&
        (cell as Cell<VALUE_TYPE, FieldTypesWithParseSupport>).metadata.converter &&
        (cell as Cell<VALUE_TYPE, FieldTypesWithParseSupport>).metadata.converter.parse != null
    );
};

const tokensToVariables = (tokens) => {
    return `:root * {
    ${Object.keys(tokens)
        .map((key) => `--${key}: ${tokens[key]};`)
        .join("\n")}
    }`;
};
