/**
 * The back navigation mode determines how the navigation stack is threated.
 *
 * NONE
 * The host can navigate back without navigating back inside
 * the web app. This is the default.
 *
 * LINEAR
 * The visited urls are stored in a stack, upon back navigation in the host,
 * the web app url is restored to the previous value.
 *
 * COMPRESSED
 * Similar to the LINEAR mode, with the exception that if a url is visited
 * again, the navigation history of the web app is dropped until that point.
 */
export type BackNavigationMode = "NONE" | "LINEAR" | "COMPRESSED";

/**
 * Additional parameters for the navigation.
 */
export interface INavigationOptions {
    /**
     * Whether the new page(s) openned on a new tab or not
     * @type {boolean}
     */
    newTab: boolean;
}

export interface IMassDataNavigationOptions extends INavigationOptions {
    /**
     * The permission contexts to be used when querying the records. If omitted, the `default` context is used.
     */
    permissionContexts?: string[];
    /**
     * Set to true if the target form should also show private records with limited fields, like private appointments.
     */
    includePrivateForeignRecords?: boolean;
}

export interface IRecordNavigationOptions extends INavigationOptions {
    /**
     * Whether the edit mode should be opened or not.
     * @type {boolean}
     */
    editMode: boolean;

    /**
     * Whether an overlay should be used or not.
     * @type {boolean}
     */
    inOverlay: boolean;
}

export interface INavigationSelection {
    gguids: string[];
    selectedGuid: string;
}

export interface INavigator {
    navigate(intent: string, options?: INavigationOptions): Promise<void>;
    navigateWithRecord(
        objectType: string,
        gguid: string,
        intent?: string,
        options?: IRecordNavigationOptions,
    ): Promise<void>;
    navigateWithRecords(
        objectType: string,
        selection: INavigationSelection,
        intent?: string,
        options?: IMassDataNavigationOptions,
    ): Promise<void>;
    navigateToDossier(
        source: ISingleSelection,
        selection?: ISingleSelection,
        intent?: string,
        navigateToDossier?: string[],
        options?: INavigationOptions,
    ): Promise<void>;
}

export interface ISingleSelection {
    objectType: string;
    gguid: string;
}

/**
 * Navigation builder for navigating without context.
 */
export interface INavigationBuilder {
    /**
     * Trigger the navigation with the configured parameters.
     * @return {Promise<void>}
     */
    navigate(): Promise<void>;

    /**
     * Set the navigation intent.
     * @param {String} intentName
     * @return {this}
     */
    withIntent(intentName: string): this;

    /**
     * Whether the new page(s) should be opened on a new tab or not. Note that opening on new tab is only supported for
     * read mode navigations.
     * @param {boolean} newTab defaults to true
     * @return {this}
     */
    openOnNewTab(newTab?: boolean): this;

    /**
     * Attaches callbacks for the resolution and/or rejection of the Promise.
     * @param onfulfilled The callback to execute when the Promise is resolved.
     * @param onrejected The callback to execute when the Promise is rejected.
     * @returns A Promise for the completion of which ever callback is executed.
     */
    then<TResult1 = void, TResult2 = never>(
        onfulfilled?: ((value: void) => TResult1 | PromiseLike<TResult1>) | undefined | null,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        onrejected?: ((reason: any) => TResult2 | PromiseLike<TResult2>) | undefined | null,
    ): Promise<TResult1 | TResult2>;

    /**
     * Attaches a callback for only the rejection of the Promise.
     * @param onrejected The callback to execute when the Promise is rejected.
     * @returns A Promise for the completion of the callback.
     */
    catch<TResult = never>(
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        onrejected?: ((reason: any) => TResult | PromiseLike<TResult>) | undefined | null,
    ): Promise<void | TResult>;
}

/**
 * Navigation builder for navigating with data obejct.
 */
export interface INavigationWithRecordBuilder extends INavigationBuilder {
    /**
     * Sets the type of the data object.
     * @param {String} objectType
     * @return {this}
     */
    withObjectType(objectType: string): this;

    /**
     * Sets the id (gguid) of the data object
     * @param {String} gguid
     * @return {this}
     */
    withGguid(gguid: string): this;

    /**
     * Indicates that the navigation should open the edit mode.
     * @return {this}
     */
    openEditMode(): this;

    /**
     * Indicates that the navigation should open an overlay.
     * @return {this}
     */
    openInOverlay(): this;
}

/**
 * Navigation builder for navigating with a list of data obejcts.
 */
export interface INavigationWithRecordsBuilder extends INavigationBuilder {
    /**
     * Sets the type of the data objects.
     * @param {String} objectType
     * @return {this}
     */
    withObjectType(objectType: string): this;
    /**
     * Sets the id (gguid) of the selected data object. Selected id should be
     * presented in the gguids list, see {@link withGguids}.
     * @param {String} selectedGguid
     * @return {this}
     */
    withSelectedGguid(selectedGguid: string): this;
    /**
     * The permission contexts to be used when querying the records. If omitted, the `default` context is used.
     * @param {string[]} permissionContexts
     * @return {this}
     */
    withPermissionContext(...permissionContexts: string[]): this;
    /**
     * Call it with true if the target form should also show private records with limited fields, like private appointments.
     * @param {string[]} includePrivateForeignRecords
     * @return {this}
     */
    includePrivateForeignRecords(includePrivateForeignRecords?: boolean): this;
    /**
     * Sets the list of the data objects ids.
     * @param {string[]} gguids
     * @return {this}
     */
    withGguids(gguids: string[]): this;
}

/**
 * Navigation builder for dossier navigation
 */
export interface INavigationWithDossierBuilder extends INavigationBuilder {
    /**
     * Sets of the object type of the source item.
     * @param {String} sourceObjectType
     * @return {this}
     */
    withSourceObjectType(sourceObjectType: string): this;

    /**
     * Sets the gguid of the source item.
     * @param {String} sourceGguid
     * @return {this}
     */
    withSourceGguid(sourceGguid: string): this;

    /**
     * Sets of the object type of the selected item.
     * @param {String} selectedObjectType
     * @return {this}
     */
    withSelectedObjectType(selectedObjectType: string): this;

    /**
     * Sets the selected data object guid, that should be member of the dossier items
     * @param {String} selectedGguid
     * @return {this}
     */
    withSelectedGguid(selectedGguid: string): this;

    /**
     * Sets the typesToShow list, which defines the available object types.
     * If it is empty the server configuration is used.
     * @param {String[]} typesToShow
     * @return {this}
     */
    withTypeToShow(typesToShow: string[]): this;
}

export class NavigationBuilder implements INavigationBuilder {
    protected _intentName: string;
    protected _newTab = false;
    private _navigation: Promise<void>;

    constructor(protected navigator: INavigator) {}

    public navigate(): Promise<void> {
        if (this._navigation) {
            return this._navigation;
        }

        this._navigation = this.invokeNavigation();
        return this._navigation;
    }

    public withIntent(intentName: string): this {
        this._intentName = intentName;
        return this;
    }

    public openOnNewTab(newTab = true): this {
        this._newTab = newTab;
        return this;
    }

    protected invokeNavigation(): Promise<void> {
        const options: INavigationOptions = {
            newTab: this._newTab,
        };
        return this.navigator.navigate(this._intentName, options);
    }

    public then<TResult1 = void, TResult2 = never>(
        onfulfilled?: ((value: void) => TResult1 | PromiseLike<TResult1>) | undefined | null,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        onrejected?: ((reason: any) => TResult2 | PromiseLike<TResult2>) | undefined | null,
    ): Promise<TResult1 | TResult2> {
        return this.navigate().then(onfulfilled, onrejected);
    }
    public catch<TResult = never>(
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        onrejected?: (reason: any) => TResult | PromiseLike<TResult>,
    ): Promise<void | TResult> {
        return this.navigate().then(null, onrejected);
    }
}

export class NavigationWithRecordBuilder extends NavigationBuilder implements INavigationWithRecordBuilder {
    protected _objectType: string;
    protected _gguid: string;
    protected _editMode = false;
    protected _inOverlay = false;

    public openEditMode(editMode = true): this {
        this._editMode = editMode;
        return this;
    }

    public openInOverlay(inOverlay = true): this {
        this._inOverlay = inOverlay;
        return this;
    }

    public withObjectType(objectType: string): this {
        this._objectType = objectType;
        return this;
    }

    public withGguid(gguid: string): this {
        this._gguid = gguid;
        return this;
    }

    protected invokeNavigation(): Promise<void> {
        const options: IRecordNavigationOptions = {
            newTab: this._newTab,
            editMode: this._editMode,
            inOverlay: this._inOverlay,
        };
        return this.navigator.navigateWithRecord(this._objectType, this._gguid, this._intentName, options);
    }
}

export class NavigationWithRecordsBuilder extends NavigationBuilder implements INavigationWithRecordsBuilder {
    protected _objectType: string;
    protected _selectedGguid: string;
    protected _gguids: string[];
    protected _permissionContexts: string[];
    protected _includePrivateForeignRecords: boolean;

    public withObjectType(objectType: string): this {
        this._objectType = objectType;
        return this;
    }

    public withSelectedGguid(selectedGguid: string): this {
        this._selectedGguid = selectedGguid;
        return this;
    }

    public withGguids(gguids: string[]): this {
        this._gguids = gguids;
        return this;
    }

    public withPermissionContext(...permissionContexts: string[]): this {
        this._permissionContexts = [...(this._permissionContexts ?? []), ...permissionContexts];
        return this;
    }

    public includePrivateForeignRecords(includePrivateForeignRecords = true): this {
        this._includePrivateForeignRecords = includePrivateForeignRecords;
        return this;
    }

    protected invokeNavigation(): Promise<void> {
        const options: IMassDataNavigationOptions = {
            newTab: this._newTab,
            permissionContexts: this._permissionContexts,
            includePrivateForeignRecords: this._includePrivateForeignRecords,
        };
        const selection: INavigationSelection = {
            selectedGuid: this._selectedGguid ? this._selectedGguid : null,
            gguids: this._gguids,
        };
        return this.navigator.navigateWithRecords(this._objectType, selection, this._intentName, options);
    }
}

export class NavigationWithDossierBuilder extends NavigationBuilder implements INavigationWithDossierBuilder {
    protected _sourceObjectType: string;
    protected _sourceGguid: string;
    protected _selectedObjectType: string;
    protected _selectedGguid: string;
    protected _typesToShow: string[];

    public withSourceObjectType(sourceObjectType: string): this {
        this._sourceObjectType = sourceObjectType;
        return this;
    }

    public withSourceGguid(sourceGguid: string): this {
        this._sourceGguid = sourceGguid;
        return this;
    }

    public withSelectedObjectType(selectedObjectType: string): this {
        this._selectedObjectType = selectedObjectType;
        return this;
    }

    public withSelectedGguid(selectedGguid: string): this {
        this._selectedGguid = selectedGguid;
        return this;
    }

    public withTypeToShow(typesToShow: string[]): this {
        this._typesToShow = typesToShow;
        return this;
    }

    protected invokeNavigation(): Promise<void> {
        const options: INavigationOptions = {
            newTab: this._newTab,
        };
        const source: ISingleSelection = {
            gguid: this._sourceGguid,
            objectType: this._sourceObjectType,
        };
        let selection: ISingleSelection;
        if (this._selectedGguid && this._selectedObjectType) {
            selection = {
                gguid: this._selectedGguid,
                objectType: this._selectedObjectType,
            };
        }
        return this.navigator.navigateToDossier(source, selection, this._intentName, this._typesToShow, options);
    }
}
